INSERT INTO metric_rule (rule_id, rule_name, rule_type, rule_definition_json, enabled) VALUES ('soil_warning_v1', '墒情预警规则V1', 'soil_warning', '{"document_name": "江苏省农业农村指挥调度平台预警规则及发布模版.pdf", "soil_warning_v1": [{"rule_name": "表层重旱预警", "condition": "water20cm < 50", "warning_level": "heavy_drought"}, {"rule_name": "表层涝渍预警", "condition": "water20cm >= 150", "warning_level": "waterlogging"}, {"rule_name": "设备故障预警", "condition": "water20cm = 0 and t20cm = 0", "warning_level": "device_fault"}], "if_not_triggered": "仍可按模板输出当前监测结果，但需明确标注为未达到预警条件"}', 1) ON DUPLICATE KEY UPDATE rule_definition_json=VALUES(rule_definition_json);
INSERT INTO soil_alert_templates (template_id, template_name, template_text, render_mode) VALUES ('soil_warning_template_v1', '墒情预警模板V1', '{{year}} 年 {{month}} 月 {{day}} 日 {{hour}} 时 {{city_name}} {{county_name}} SN 编号 {{device_sn}} 土壤墒情仪监测到相对含水量 {{water20cm}}%，预警等级 {{warning_level}}，请大田/设施大棚/林果相关主体关注！', 'strict') ON DUPLICATE KEY UPDATE template_text=VALUES(template_text);
